3	/**
4	 * API Response Helpers
5	 * Единообразный формат ответов API
6	 */
7	
8	export interface ApiErrorItem {
9	  field?: string;
10	  message: string;
11	}
12	
13	export interface ApiResponse<T = unknown> {
14	  success: boolean;
15	  message?: string;
16	  data?: T;
17	  errors?: ApiErrorItem[];
18	  stack?: string;
19	}
20	
21	/**
22	 * Успешный ответ
23	 */
24	export function success<T>(res: Response, data?: T, message?: string, statusCode = 200): void {
25	  const body: ApiResponse<T> = {
26	    success: true,
27	    ...(message && { message }),
28	    ...(data !== undefined && { data })
29	  };
30	  res.status(statusCode).json(body);
31	}
32	
33	/**
34	 * Ответ об ошибке (единый формат)
35	 */
36	export function error(
37	  res: Response,
38	  message: string,
39	  statusCode = 400,
40	  errors?: ApiErrorItem[]
41	): void {
42	  const body: ApiResponse = {
43	    success: false,
44	    message,
45	    ...(errors && errors.length > 0 && { errors })
46	  };
47	  res.status(statusCode).json(body);
48	}
49	
50	/**
51	 * 404 Not Found
52	 */
53	export function notFound(res: Response, message = 'Resource not found'): void {
54	  error(res, message, 404);
55	}
56	
57	/**
58	 * 401 Unauthorized
59	 */
60	export function unauthorized(res: Response, message = 'Not authenticated'): void {
61	  error(res, message, 401);
62	}
